/**
 * @summary List complaints
 */
export const getGetComplaintsUrl = (params?: GetComplaintsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/complaints?${stringifiedParams}`
    : `/api/complaints`;
};

export const getComplaints = async (
  params?: GetComplaintsParams,
  options?: RequestInit,
): Promise<ComplaintsListResponse> => {
  return customFetch<ComplaintsListResponse>(getGetComplaintsUrl(params), {
    ...options,
    method: "GET",
  });
};

